# Algorithm 2 DRL: Deep Reinforcement Learning Based Framework of Reinforcement Learning

1:         Initialize memory pool D with size ν, action-value function and target Q-function with random weights θ ;
2:     for epi := 1 to 3 do
3:      Initialize state  s1 observed from environment;
4:      f lag := 0;
5:      for z := 1 to Z     do
6:       Select a random action az with probability ε or az := arg maxa∈A Q(sz, a; θz) with probability 1 − ε;
7:       Execute action az in emulator, observe reward R(sz, az) and new state sz+1 from environment;
8:       if R(sz, az) = −∞ then
9:            Break;
10:       end if
11:       Store (sz, az, R(sz, az), sz+1) into D;
12:       Sample random minibatch of transitions from D;
13:       if episode terminates at step z + 1 then
14:            Q(sz, az) := R(sz, az);
15:       else
16:            Update Q(sz, az) by (56);
17:       end if
18:       Perform a gradient descent step by (60);
19:       Every ι steps reset Qtarget (sz, az) := Q(sz, az);
20:       if z ≥ 0 and R(sz, az) ≤ 0, ∀z ∈ [z − 0, z] then
21:                f lag := 1;
22:       end if
23:       if z = |A| + 1 or f lag then
24:            Break;
25:       end if
26:       end for
27:     end for
28:     return A.

